// Single source of truth → all three clients.
//
// Reads deployments/base-sepolia.json (which the deploy scripts write) and
// generates the contract-address files for mobile (Dart), the SDK (TypeScript),
// and the executor (CommonJS). Run after EVERY redeploy, from the repo root:
//
//   node scripts/gen-addresses.mjs
//
// Then commit the generated files. No contract address is ever hand-copied into
// a client again (the cause of the #147 / #151 staleness bugs).

import { readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const repoRoot = join(dirname(fileURLToPath(import.meta.url)), "..");
const json = JSON.parse(
  readFileSync(join(repoRoot, "deployments", "base-sepolia.json"), "utf8")
);

const c = json.contracts ?? {};
const deployedAt = json.deployedAt ?? "unknown";
const chainId = json.chainId ?? 84532;
const deployBlock = json.deployBlock ?? 0;
// MaktubFlash can be on an older stack than the Beat redeploy (it is not
// redeployed every freeze), so its event-log scan floor is tracked separately.
// Falls back to deployBlock when the deploy record doesn't carry it.
const flashDeployBlock = json.flashDeployBlock ?? deployBlock;

function addr(key) {
  const v = c[key];
  if (!v) throw new Error(`contracts.${key} missing in deployments/base-sepolia.json`);
  return v;
}

const A = {
  MaktubCore: addr("MaktubCore"),
  RecipientRegistry: addr("RecipientRegistry"),
  RecipientRegistryV2: addr("RecipientRegistryV2"),
  MaktubFlash: addr("MaktubFlash"),
  MktbToken: addr("MktbToken"),
  ExecutorRewards: addr("ExecutorRewards"),
  ExecutionRelay: addr("ExecutionRelay"),
  MktbGovernance: addr("MktbGovernance"),
};

const banner =
  `// GENERATED by scripts/gen-addresses.mjs — DO NOT EDIT.\n` +
  `// Single source of truth: deployments/base-sepolia.json (stack of ${deployedAt}).\n` +
  `// Regenerate after any redeploy: node scripts/gen-addresses.mjs\n`;

// ── 1. Mobile (Dart) ───────────────────────────────────────────────────────
const dart = `${banner}
/// Deployed contract addresses, generated from the canonical deployments
/// record so they can never drift per-file.
class ContractAddresses {
  ContractAddresses._();

  static const int chainId = ${chainId};
  static const String deployedAt = '${deployedAt}';
  static const int deployBlock = ${deployBlock};

  /// Event-log scan floor for MaktubFlash. Tracked separately from
  /// [deployBlock] because Flash is not redeployed every Beat freeze — using
  /// the Beat block here would silently hide messages older than the freeze.
  static const int flashDeployBlock = ${flashDeployBlock};

  static const String maktubCore = '${A.MaktubCore}';
  static const String recipientRegistry = '${A.RecipientRegistry}';
  static const String recipientRegistryV2 = '${A.RecipientRegistryV2}';
  static const String maktubFlash = '${A.MaktubFlash}';
  static const String mktbToken = '${A.MktbToken}';
  static const String executorRewards = '${A.ExecutorRewards}';
  static const String executionRelay = '${A.ExecutionRelay}';
}
`;
writeFileSync(join(repoRoot, "mobile/lib/services/contract_addresses.g.dart"), dart);

// ── 2. SDK (TypeScript) ────────────────────────────────────────────────────
const ts = `${banner}
export const SEPOLIA_CHAIN_ID = ${chainId};
export const SEPOLIA_DEPLOY_BLOCK = ${deployBlock};
// Flash is not redeployed every Beat freeze — its log scans use its own floor.
export const SEPOLIA_FLASH_DEPLOY_BLOCK = ${flashDeployBlock};

export const SEPOLIA_CONTRACTS = {
  maktubCore: "${A.MaktubCore}",
  recipientRegistry: "${A.RecipientRegistry}",
  mktbToken: "${A.MktbToken}",
  executorRewards: "${A.ExecutorRewards}",
  mktbGovernance: "${A.MktbGovernance}",
  executionRelay: "${A.ExecutionRelay}",
  recipientRegistryV2: "${A.RecipientRegistryV2}",
  maktubFlash: "${A.MaktubFlash}",
};
`;
writeFileSync(join(repoRoot, "sdk/src/constants/sepolia_addresses.generated.ts"), ts);

// ── 3. Executor (CommonJS) ─────────────────────────────────────────────────
const js = `${banner}
module.exports = {
  deployBlock: ${deployBlock},
  contracts: {
    MktbToken: "${A.MktbToken}",
    ExecutorRewards: "${A.ExecutorRewards}",
    MaktubCore: "${A.MaktubCore}",
    RecipientRegistry: "${A.RecipientRegistry}",
    ExecutionRelay: "${A.ExecutionRelay}",
  },
};
`;
writeFileSync(join(repoRoot, "executor/src/addresses.generated.js"), js);

console.log(`Generated mobile + SDK + executor addresses (stack ${deployedAt}).`);
